      .from('kira_conversations')
      .update({ pinned: !currentlyPinned })
      .eq('id', chatId);
    if (!error) {
      setChatHistories(prev => prev.map(c =>
        c.id === chatId ? { ...c, pinned: !currentlyPinned } : c
