I want to improve the whole memory logic of our application using Langchain as the core infra. Please be aware of tokens during this implementation. Additionally, here is an example of an implementation file: use it for reference only. For yours, use the latest libraries and methods   // lib/kira-memory.ts

import { ChatOpenAI, OpenAIEmbeddings } from "@langchain/openai";
import { SupabaseVectorStore } from "@langchain/community/vectorstores/supabase";
import {
  HumanMessage,
  AIMessage,
  SystemMessage,
} from "@langchain/core/messages";

import { createClient } from "@supabase/supabase-js";

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

const llm = new ChatOpenAI({
  model: "gpt-4.1-mini",
  temperature: 0.7,
  apiKey: process.env.OPENAI_API_KEY!,
});

const embeddings = new OpenAIEmbeddings({
  model: "text-embedding-3-small",
  apiKey: process.env.OPENAI_API_KEY!,
});

/*
|--------------------------------------------------------------------------
| VECTOR STORE
|--------------------------------------------------------------------------
*/

const vectorStore = new SupabaseVectorStore(embeddings, {
  client: supabase,
  tableName: "kira_memories",
  queryName: "match_kira_memories",
});

/*
|--------------------------------------------------------------------------
| TYPES
|--------------------------------------------------------------------------
*/

type ChatMessage = {
  role: "user" | "assistant";
  content: string;
};

type GenerateReplyParams = {
  userId: string;
  conversationId: string;
  prompt: string;
};

/*
|--------------------------------------------------------------------------
| MAIN AI PIPELINE
|--------------------------------------------------------------------------
*/

export async function generateKiraReply({
  userId,
  conversationId,
  prompt,
}: GenerateReplyParams) {
  /*
  |--------------------------------------------------------------------------
  | 1. FETCH USER PROFILE MEMORY
  |--------------------------------------------------------------------------
  */

  const { data: profile } = await supabase
    .from("profiles")
    .select(`
      display_name,
      bio,
      user_type,
      kira_memory
    `)
    .eq("id", userId)
    .single();

  /*
  |--------------------------------------------------------------------------
  | 2. FETCH RECENT CHAT HISTORY
  |--------------------------------------------------------------------------
  */

  const { data: recentMessages } = await supabase
    .from("chat_messages")
    .select("*")
    .eq("conversation_id", conversationId)
    .order("created_at", { ascending: false })
    .limit(12);

  const orderedMessages = (recentMessages || []).reverse();

  /*
  |--------------------------------------------------------------------------
  | 3. RETRIEVE RELEVANT LONG-TERM MEMORIES
  |--------------------------------------------------------------------------
  */

  const relevantMemories = await vectorStore.similaritySearch(
    `${prompt}`,
    5,
    {
      user_id: userId,
    }
  );

  const formattedMemories = relevantMemories
    .map((m) => `- ${m.pageContent}`)
    .join("\n");

  /*
  |--------------------------------------------------------------------------
  | 4. FETCH CONVERSATION SUMMARY
  |--------------------------------------------------------------------------
  */

  const { data: summaryRow } = await supabase
    .from("conversation_summaries")
    .select("summary")
    .eq("conversation_id", conversationId)
    .single();

  const summary = summaryRow?.summary || "";

  /*
  |--------------------------------------------------------------------------
  | 5. BUILD SYSTEM CONTEXT
  |--------------------------------------------------------------------------
  */

  const systemPrompt = `
IDENTITY
You are Kira, Crevia's intelligent operational AI.

COMMUNICATION
- Speak naturally
- Be sharp, concise, helpful
- Never sound robotic
- Never use markdown
- Never hallucinate

USER PROFILE
Name: ${profile?.display_name || "Unknown"}
Bio: ${profile?.bio || "None"}
Type: ${profile?.user_type || "Unknown"}

LONG-TERM MEMORY
${formattedMemories || "None"}

CONVERSATION SUMMARY
${summary || "No previous summary"}
`;

  /*
  |--------------------------------------------------------------------------
  | 6. BUILD MESSAGE STACK
  |--------------------------------------------------------------------------
  */

  const messages = [
    new SystemMessage(systemPrompt),

    ...orderedMessages.map((msg: ChatMessage) => {
      if (msg.role === "assistant") {
        return new AIMessage(msg.content);
      }

      return new HumanMessage(msg.content);
    }),

    new HumanMessage(prompt),
  ];

  /*
  |--------------------------------------------------------------------------
  | 7. GENERATE RESPONSE
  |--------------------------------------------------------------------------
  */

  const response = await llm.invoke(messages);

  const reply = response.content.toString();

  /*
  |--------------------------------------------------------------------------
  | 8. SAVE USER MESSAGE
  |--------------------------------------------------------------------------
  */

  await supabase.from("chat_messages").insert([
    {
      conversation_id: conversationId,
      user_id: userId,
      role: "user",
      content: prompt,
    },
  ]);

  /*
  |--------------------------------------------------------------------------
  | 9. SAVE AI RESPONSE
  |--------------------------------------------------------------------------
  */

  await supabase.from("chat_messages").insert([
    {
      conversation_id: conversationId,
      user_id: userId,
      role: "assistant",
      content: reply,
    },
  ]);

  /*
  |--------------------------------------------------------------------------
  | 10. MEMORY EXTRACTION
  |--------------------------------------------------------------------------
  */

  await extractAndStoreMemory({
    userId,
    prompt,
    reply,
  });

  /*
  |--------------------------------------------------------------------------
  | 11. UPDATE CONVERSATION SUMMARY
  |--------------------------------------------------------------------------
  */

  await updateConversationSummary({
    userId,
    conversationId,
  });

  return reply;
}

/*
|--------------------------------------------------------------------------
| MEMORY EXTRACTION
|--------------------------------------------------------------------------
*/

async function extractAndStoreMemory({
  userId,
  prompt,
  reply,
}: {
  userId: string;
  prompt: string;
  reply: string;
}) {
  const extractionPrompt = `
Extract ONLY durable long-term memories from this interaction.

GOOD MEMORIES:
- goals
- business info
- preferences
- projects
- workflows
- relationships
- recurring needs

BAD MEMORIES:
- greetings
- filler
- temporary requests
- jokes

Return JSON array only.

Conversation:

USER:
${prompt}

ASSISTANT:
${reply}
`;

  const extraction = await llm.invoke([
    new SystemMessage(
      "You extract durable user memories."
    ),
    new HumanMessage(extractionPrompt),
  ]);

  try {
    const parsed = JSON.parse(
      extraction.content.toString()
    );

    if (!Array.isArray(parsed)) return;

    for (const memory of parsed) {
      if (!memory?.content) continue;

      await vectorStore.addDocuments([
        {
          pageContent: memory.content,
          metadata: {
            user_id: userId,
            type: memory.type || "general",
            importance: memory.importance || 5,
          },
        },
      ]);
    }
  } catch (err) {
    console.error("Memory extraction failed:", err);
  }
}

/*
|--------------------------------------------------------------------------
| CONVERSATION SUMMARY UPDATER
|--------------------------------------------------------------------------
*/

async function updateConversationSummary({
  userId,
  conversationId,
}: {
  userId: string;
  conversationId: string;
}) {
  const { data: messages } = await supabase
    .from("chat_messages")
    .select("*")
    .eq("conversation_id", conversationId)
    .order("created_at", {
      ascending: true,
    })
    .limit(50);

  const transcript = (messages || [])
    .map(
      (m) =>
        `${m.role.toUpperCase()}: ${m.content}`
    )
    .join("\n");

  const summaryPrompt = `
Summarize this conversation for future AI context.

Focus on:
- ongoing projects
- important decisions
- user goals
- unresolved tasks
- operational context

Keep concise but useful.
`;

  const summaryResponse = await llm.invoke([
    new SystemMessage(
      "You summarize conversations."
    ),
    new HumanMessage(
      `${summaryPrompt}\n\n${transcript}`
    ),
  ]);

  const summary =
    summaryResponse.content.toString();

  await supabase
    .from("conversation_summaries")
    .upsert({
      conversation_id: conversationId,
      user_id: userId,
      summary,
    });
}

